// // This module is designed to count down from 15 to 0 on the positive edge of the clock and reset to 15 when the reset signal is high.
module up_counter (  
    input clk,  
    input reset,  
    output reg [3:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 4'b0000;  
        end else begin  
            count <= count + 1;  
        end  
    end  
endmodule
